// src/modules/user/user.services.ts
import bcrypt from "bcryptjs";
var registerIntroDB = async (payload) => {
  const { name, email, password, phone, address, role } = payload;
  const userExists = await prisma.user.findUnique({ where: { email } });
  if (userExists) {
    throw new Error("User already exists");
  }
  const hashedPassword = await bcrypt.hash(
    password,
    Number(config_default.bcrypt_salt_rounds)
  );
  const createUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashedPassword,
      role
    }
  });
  const user = await prisma.user.findUnique({
    where: {
      email: createUser.email
    },
    omit: {
      password: true
    }
  });
  return user;
};
var getMyProfile = async (payload) => {
  const { name, email, role, id } = payload;
  const user = await prisma.user.findUnique({
    where: { email, name, role, id },
    omit: { password: true }
  });
  if (!user) {
    throw new Error("User not found");
  }
  if (user.status === "BLOCKED") {
    throw new Error("your account has been bloked. please contact support");
  }
  return user;
};
