import bcrypt2 from "bcryptjs";
var loginUserFromDB = async (payload) => {
  const { email, password } = payload;
  if (!email || !password) {
    throw new Error("Provied email and password");
  }
  const user = await prisma.user.findUnique({ where: { email } });
  if (!user) {
    throw new Error("User not found");
  }
  const isMatchPassword = await bcrypt2.compare(password, user.password);
  if (!isMatchPassword) {
    throw new Error("Invaild creadintials");
  }
  if (user.status === "BLOCKED") {
    throw new Error("your account has been bloked. please contact support");
  }
  const JwtPayload2 = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(
    JwtPayload2,
    config_default.jwt_access_secret,
    config_default.jwt_access_expire_in
  );
  const refreshToken3 = jwtUtils.createToken(
    JwtPayload2,
    config_default.jwt_refresh_secret,
    config_default.jwt_access_expire_in
  );
  const loginUser = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role,
    status: user.status,
    createdAt: user.createdAt
  };
  return {
    loginUser,
    accessToken,
    refreshToken: refreshToken3
  };
};
var refreshToken = async (token) => {
  if (!token) {
    throw new Error("Your token missing plesse login agin");
  }
  const verifiedToken2 = jwtUtils.verifiedToken(
    token,
    config_default.jwt_refresh_secret
  );
  if (!verifiedToken2.success) {
    throw new Error(verifiedToken2.error);
  }
  const { email, name, id, role } = verifiedToken2.data;
  const user = await prisma.user.findUnique({
    where: { id, email, name, role }
  });
  if (!user) {
    throw new Error("User not found please log in again");
  }
  if (user.status === "BLOCKED") {
    throw new Error("your account has been bloked. please contact support");
  }
  const JwtPayload2 = {
    id: user.id,
    name: user.name,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(
    JwtPayload2,
    config_default.jwt_access_secret,
    config_default.jwt_access_expire_in
  );
  return { accessToken };
};
var authServies = {
  loginUserFromDB,
  refreshToken
};

// src/modules/auth/auth.controller.ts
var login = catchAsync(
  async (req, res, next) => {
    const payload = req.body;
    const { loginUser, accessToken, refreshToken: refreshToken3 } = await authServies.loginUserFromDB(payload);
    res.cookie("accessToken", accessToken, {
      httpOnly: true,
      secure: false,
      sameSite: "none",
      maxAge: 1e3 * 60 * 60 * 24
      //24 hour one day
    });
    res.cookie("refreshToken", refreshToken3, {
      httpOnly: true,
      secure: false,
      sameSite: "none",
      maxAge: 1e3 * 60 * 60 * 24 * 7
    });
    sendResponse(res, {
      success: true,
      statusCode: httpStatus4.OK,
      message: "user login successfully",
      data: {
        user: loginUser,
        accessToken,
        refreshToken: refreshToken3
      }
    });
  }
);
var refreshToken2 = catchAsync(
  async (req, res, next) => {
    const token = req.cookies.refreshToken;
    console.log(token);
    const { accessToken } = await authServies.refreshToken(token);
    res.cookie("accessToken", accessToken, {
      httpOnly: true,
      secure: false,
      sameSite: "none",
      maxAge: 1e3 * 60 * 60 * 24
      //24 hour one day
    });
    sendResponse(res, {
      success: true,
      statusCode: httpStatus4.OK,
      message: "generated refreshToken to accessToken successfully",
      data: {
        accessToken
      }
    });
  }
);
var authController = {
  login,
  refreshToken: refreshToken2
};

