var getAllUsers = async (query) => {
  const {
    search,
    role,
    status,
    sortBy = "createdAt",
    sortOrder = "desc",
    limit = 10,
    page = 1
  } = query;
  const skip = (parseInt(page) - 1) * parseInt(limit);
  const where = {};
  if (search) {
    where.OR = [
      { name: { contains: search, mode: "insensitive" } },
      { email: { contains: search, mode: "insensitive" } },
      { phone: { contains: search, mode: "insensitive" } }
    ];
  }
  if (role) {
    where.role = role;
  }
  if (status) {
    where.status = status;
  }
  const [users, total] = await Promise.all([
    prisma.user.findMany({
      where,
      select: {
        id: true,
        name: true,
        email: true,
        phone: true,
        role: true,
        status: true,
        address: true,
        profileImage: true,
        avatar: true,
        createdAt: true,
        updatedAt: true,
        _count: {
          select: {
            properties: true,
            reviews: true,
            landlordRequests: true,
            tenantRequests: true
          }
        }
      },
      skip,
      take: parseInt(limit),
      orderBy: {
        [sortBy]: sortOrder
      }
    }),
    prisma.user.count({ where })
  ]);
  const formattedUsers = users.map((user) => ({
    id: user.id,
    name: user.name,
    email: user.email,
    phone: user.phone,
    role: user.role,
    status: user.status,
    address: user.address,
    profileImage: user.profileImage,
    avatar: user.avatar,
    createdAt: user.createdAt,
    updatedAt: user.updatedAt,
    stats: {
      totalProperties: user._count.properties || 0,
      totalReviews: user._count.reviews || 0,
      totalLandlordRequests: user._count.landlordRequests || 0,
      totalTenantRequests: user._count.tenantRequests || 0,
      totalRequests: (user._count.landlordRequests || 0) + (user._count.tenantRequests || 0)
    }
  }));
  return {
    data: formattedUsers,
    pagination: {
      total,
      page: parseInt(page),
      limit: parseInt(limit),
      totalPages: Math.ceil(total / parseInt(limit))
    }
  };
};
var updateUser = async (userId, payload) => {
  const { name, email, phone, role, status, address, profileImage, avatar } = payload;
  const existingUser = await prisma.user.findUnique({
    where: { id: userId }
  });
  if (!existingUser) {
    throw new Error("User not found");
  }
  if (email && email !== existingUser.email) {
    const emailExists = await prisma.user.findUnique({
      where: { email }
    });
    if (emailExists) {
      throw new Error(`Email "${email}" already exists`);
    }
  }
  const updateData = {};
  if (name) updateData.name = name;
  if (email) updateData.email = email;
  if (phone) updateData.phone = phone;
  if (role) updateData.role = role;
  if (status) updateData.status = status;
  if (address) updateData.address = address;
  if (profileImage) updateData.profileImage = profileImage;
  if (avatar) updateData.avatar = avatar;
  const user = await prisma.user.update({
    where: { id: userId },
    data: updateData,
    select: {
      id: true,
      name: true,
      email: true,
      phone: true,
      role: true,
      status: true,
      address: true,
      profileImage: true,
      avatar: true,
      createdAt: true,
      updatedAt: true
    }
  });
  return {
    message: `User "${user.name}" updated successfully by Admin`,
    user
  };
};
