var adminUpdateRentalStatus = async (rentalId, payload) => {
  const { status } = payload;
  if (!status) {
    throw new Error("Status is required");
  }
  const validStatuses = ["PENDING", "APPROVED", "REJECTED", "CANCELLED"];
  if (!validStatuses.includes(status)) {
    throw new Error(
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }
  const rental = await prisma.rentalRequest.findUnique({
    where: { id: rentalId },
    include: {
      property: {
        select: {
          id: true,
          title: true,
          availability: true,
          landlordId: true
        }
      }
    }
  });
  if (!rental) {
    throw new Error("Rental request not found");
  }
  const updatedRental = await prisma.rentalRequest.update({
    where: { id: rentalId },
    data: { status },
    include: {
      property: {
        select: {
          id: true,
          title: true,
          location: true,
          price: true,
          availability: true
        }
      },
      tenant: {
        select: {
          id: true,
          name: true,
          email: true,
          phone: true
        }
      },
      landlord: {
        select: {
          id: true,
          name: true,
          email: true,
          phone: true
        }
      }
    }
  });
  if (status === "APPROVED") {
    await prisma.property.update({
      where: { id: rental.propertyId },
      data: { availability: "RENTED" }
    });
  }
  if (status === "REJECTED" || status === "CANCELLED") {
    const otherApproved = await prisma.rentalRequest.findFirst({
      where: {
        propertyId: rental.propertyId,
        id: { not: rentalId },
        status: "APPROVED"
      }
    });
    if (!otherApproved) {
      await prisma.property.update({
        where: { id: rental.propertyId },
        data: { availability: "AVAILABLE" }
      });
    }
  }
  return {
    message: `Rental request ${status.toLowerCase()} successfully by Admin`,
    rental: updatedRental
  };
};
var adminDeleteRental = async (rentalId) => {
  const rental = await prisma.rentalRequest.findUnique({
    where: { id: rentalId },
    include: {
      payment: true
    }
  });
  if (!rental) {
    throw new Error("Rental request not found");
  }
  if (rental.payment) {
    throw new Error("Cannot delete rental request with existing payment");
  }
  await prisma.rentalRequest.delete({
    where: { id: rentalId }
  });
  return {
    message: "Rental request deleted successfully by Admin",
    deletedRental: {
      id: rental.id,
      propertyId: rental.propertyId,
      tenantId: rental.tenantId,
      landlordId: rental.landlordId,
      status: rental.status
    }
  };
};
