var createRentalRequest = async (tenantId, payload) => {
  if (!payload) {
    throw new Error("Request body is required");
  }
  const { propertyId, message, startDate, endDate } = payload;
  if (!tenantId) {
    throw new Error("User ID is required");
  }
  if (!propertyId) {
    throw new Error("Property ID is required");
  }
  if (!startDate) {
    throw new Error("Start date is required");
  }
  if (!endDate) {
    throw new Error("End date is required");
  }
  const property = await prisma.property.findUnique({
    where: { id: propertyId },
    include: {
      user: {
        select: {
          id: true,
          name: true,
          email: true,
          phone: true
        }
      }
    }
  });
  if (!property) {
    throw new Error("Property not found");
  }
  if (property.availability !== "AVAILABLE") {
    throw new Error("Property is not available for rent");
  }
  if (property.landlordId === tenantId) {
    throw new Error("You cannot rent your own property");
  }
  const start = new Date(startDate);
  const end = new Date(endDate);
  if (start >= end) {
    throw new Error("End date must be after start date");
  }
  if (start < /* @__PURE__ */ new Date()) {
    throw new Error("Start date cannot be in the past");
  }
  const existingRequest = await prisma.rentalRequest.findFirst({
    where: {
      propertyId,
      tenantId,
      status: {
        in: ["PENDING", "APPROVED"]
      }
    }
  });
  if (existingRequest) {
    throw new Error("You already have a pending or approved request for this property");
  }
  const overlappingRequests = await prisma.rentalRequest.findMany({
    where: {
      propertyId,
      status: "APPROVED",
      OR: [
        {
          AND: [
            { startDate: { lte: end } },
            { endDate: { gte: start } }
          ]
        }
      ]
    }
  });
  if (overlappingRequests.length > 0) {
    throw new Error("Property is already booked for these dates");
  }
  const rentalRequest = await prisma.rentalRequest.create({
    data: {
      propertyId,
      tenantId,
      landlordId: property.landlordId,
      message: message || "",
      startDate: start,
      endDate: end,
      status: "PENDING"
    },
    include: {
      property: {
        select: {
          id: true,
          title: true,
          location: true,
          price: true,
          images: true,
          availability: true
        }
      },
      tenant: {
        select: {
          id: true,
          name: true,
          email: true,
          phone: true,
          profileImage: true
        }
      },
      landlord: {
        select: {
          id: true,
          name: true,
          email: true,
          phone: true,
          profileImage: true
        }
      }
    }
  });
  return {
    message: "Rental request created successfully",
    rentalRequest
  };
};
