        line_items: [
          {
            price_data: {
              currency: "usd",
              product_data: {
                name: `Rent Payment: ${rentalRequest.property?.title || "Property"}`,
                description: `Payment for ${rentalRequest.property?.title || "Property"}`
              },
              unit_amount: Math.round(amountInNumber * 100)
            },
            quantity: 1
          }
        ],
        mode: "payment",
        success_url: `${config_default.app_url}/payment/success?session_id={CHECKOUT_SESSION_ID}`,
        cancel_url: `${config_default.app_url}/payment/cancel?session_id={CHECKOUT_SESSION_ID}`,
        metadata: {
          paymentId: payment.id,
          rentalRequestId: payment.rentalRequestId,
          tenantId,
          propertyId: rentalRequest.propertyId
        },
